function debounce(fn, delay, { leading = false, trailing = true } = {}) {
  let timer = null;
  return function(...args) {
    const context = this;
    const isInvoked = leading && !timer;

    clearTimeout(timer);

    timer = setTimeout(() => {
      timer = null;
      if (trailing && !isInvoked) fn.apply(context, args);
    }, delay);

    if (isInvoked) fn.apply(context, args);
  };
}

