function limitConcurrency(tasks, limit) {
  return new Promise((resolve) => {
    const results = [];
    let active = 0;
    let nextIdx = 0;
    let completed = 0;

    function run() {
      if (completed === tasks.length) return resolve(results);
      while (active < limit && nextIdx < tasks.length) {
        const idx = nextIdx++;
        active++;
        tasks[idx]().then(val => {
          results[idx] = val;
          active--;
          completed++;
          run();
        });
      }
    }
    run();
  });
}

