      acc = curr;
      hasAccumulator = true;
      promise = Promise.resolve(acc);
    } else {
      promise = Promise.resolve(asyncReducer(currentAcc, curr, index - 1, arr));
    }

    return promise.then(nextAcc => execute(nextAcc));
  }

  return execute(acc);
}
