  if (typeof fn !== 'function') throw new TypeError('Expected a function');

  let active = true;
  let timeoutId = null;
  let expectedTime = Date.now() + delay;

  function run() {
    if (!active) return;

    Promise.resolve(fn())
      .then(() => {
        if (!active) return;
        const now = Date.now();
        // Calculate drift offset (expected time vs actual invocation time)
        const drift = now - expectedTime;
