        // Continue loop even on failures
        if (active) {
          expectedTime = Date.now() + delay;
          timeoutId = setTimeout(run, delay);
        }
      });
  }

  timeoutId = setTimeout(run, delay);

  return {
    stop() {
      active = false;
      if (timeoutId) {
        clearTimeout(timeoutId);
        timeoutId = null;
      }
    }
  };
