function debounce(fn, delay) {
  if (typeof fn !== 'function') throw new TypeError('Expected a function');
  let timer = null;
  let lastArgs = null;
  let lastThis = null;

  const debounced = function(...args) {
    lastArgs = args;
    lastThis = this;

    if (timer) clearTimeout(timer);

    timer = setTimeout(() => {
      fn.apply(lastThis, lastArgs);
      timer = null;
      lastArgs = null;
      lastThis = null;
    }, delay);
  };

