    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = null;
    lastThis = null;
  };

  debounced.flush = () => {
    if (timer) {
      fn.apply(lastThis, lastArgs);
      debounced.cancel();
    }
  };

  debounced.pending = () => timer !== null;

  return debounced;
}
```

