class Trie {
  constructor() { this.root = {}; }
  insert(w) {
    let curr = this.root;
    for (const c of w) {
      curr[c] = curr[c] || {};
      curr = curr[c];
    }
    curr.isWord = true;
  }
  search(prefix) {
    let curr = this.root;
    for (const c of prefix) {
      if (!curr[c]) return [];
      curr = curr[c];
    }
    const results = [];
    function collect(node, s) {
      if (node.isWord) results.push(s);
      for (const k of Object.keys(node)) {
        if (k !== 'isWord') collect(node[k], s + k);
      }
    }
    collect(curr, prefix);
    return results;
  }
}
