class Deque {
  constructor() {
    this.items = {};
    this.front = 0;
    this.rear = 0;
  }

  addFirst(x) {
    this.front--;
    this.items[this.front] = x;
  }

  addLast(x) {
    this.items[this.rear] = x;
    this.rear++;
  }

  removeFirst() {
    if (this.isEmpty()) return undefined;
    const item = this.items[this.front];
    delete this.items[this.front];
    this.front++;
