      }
      return v;
    },
    set(target, prop, value) {
      target[prop] = value;
      return true;
    }
  };
  const rootCopy = Array.isArray(base) ? [...base] : { ...base };
  const rootProxy = new Proxy(rootCopy, handler);
  recipe(rootProxy);
  return rootCopy;
}
