      const oldest = this.cache.keys().next().value;
      const oldestVal = this.cache.get(oldest);
      this.size -= (oldest.length + JSON.stringify(oldestVal).length);
      this.cache.delete(oldest);
    }
    this.cache.set(key, val);
    this.size += itemSize;
    return val;
  }
}
