class WeakTracker {
  constructor() {
    this.tracker = new WeakMap();
  }

  track(obj, meta) {
    if (obj === null || (typeof obj !== 'object' && typeof obj !== 'function')) {
      throw new TypeError('WeakTracker keys must be objects or functions');
    }
    this.tracker.set(obj, {
      meta,
      timestamp: Date.now(),
      accessCount: 0
