  get(obj) {
    const entry = this.tracker.get(obj);
    if (entry) {
      entry.accessCount++;
    }
    return entry;
  }

  has(obj) {
    return this.tracker.has(obj);
  }

  untrack(obj) {
    return this.tracker.delete(obj);
  }
}
