function customRange(start, end, step = 1) {
  return {
    [Symbol.iterator]() {
      let curr = start;
      const s = typeof step === 'number' && step !== 0 ? step : 1;

      return {
        next() {
          const isDone = s > 0 ? curr >= end : curr <= end;
          if (!isDone) {
            const val = curr;
            curr += s;
            return { value: val, done: false };
          }
          return { done: true };
        }
      };
    }
  };
}
